import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET

// Data Models
data class User(
    val id: Int,
    val name: String,
    val email: String,
    val company: Company
) {
    data class Company(
        val name: String
    )
}

// API Service
interface UserApiService {
    @GET("users")
    suspend fun getUsers(): List<User>
}

object RetrofitClient {
    private const val BASE_URL = "https://jsonplaceholder.typicode.com/"

    val apiService: UserApiService by lazy {
        Retrofit.Builder()
            .baseUrl(BASE_URL)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(UserApiService::class.java)
    }
}

// RecyclerView Adapter
class UsersAdapter(private val onUserClick: (User) -> Unit) :
    RecyclerView.Adapter<UsersAdapter.UserViewHolder>() {

    private var users: List<User> = emptyList()

    fun submitList(newUsers: List<User>) {
        users = newUsers
        notifyDataSetChanged()
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int): UserViewHolder {
        val view = LayoutInflater.from(parent.context)
            .inflate(R.layout.item_user, parent, false)
        return UserViewHolder(view)
    }

    override fun onBindViewHolder(holder: UserViewHolder, position: Int) {
        holder.bind(users[position])
    }

    override fun getItemCount(): Int = users.size

    inner class UserViewHolder(itemView: View) : RecyclerView.ViewHolder(itemView) {
        private val nameTextView: TextView = itemView.findViewById(R.id.nameTextView)
        private val emailTextView: TextView = itemView.findViewById(R.id.emailTextView)
        private val companyTextView: TextView = itemView.findViewById(R.id.companyTextView)
        private val avatarTextView: TextView = itemView.findViewById(R.id.avatarTextView)

        fun bind(user: User) {
            nameTextView.text = user.name
            emailTextView.text = user.email
            companyTextView.text = user.company.name
            avatarTextView.text = user.name.first().toString().uppercase()

            itemView.setOnClickListener {
                onUserClick(user)
            }
        }
    }
}

// Main Fragment
class UsersFragment : Fragment() {

    private lateinit var recyclerView: RecyclerView
    private lateinit var adapter: UsersAdapter
    private var _binding: FragmentUsersBinding? = null
    private val binding get() = _binding!!

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        _binding = FragmentUsersBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        setupRecyclerView()
        loadUsers()
    }

    private fun setupRecyclerView() {
        adapter = UsersAdapter { user ->
            // Navigate to user detail
            val action = UsersFragmentDirections.actionUsersToUserDetail(user)
            findNavController().navigate(action)
        }

        binding.recyclerView.apply {
            layoutManager = LinearLayoutManager(requireContext())
            adapter = this@UsersFragment.adapter
        }
    }

    private fun loadUsers() {
        binding.progressBar.visibility = View.VISIBLE

        viewLifecycleOwner.lifecycleScope.launch {
            try {
                val users = RetrofitClient.apiService.getUsers()
                adapter.submitList(users)
                binding.progressBar.visibility = View.GONE
            } catch (e: Exception) {
                binding.progressBar.visibility = View.GONE
                Snackbar.make(
                    binding.root,
                    "Failed to load users: ${e.localizedMessage}",
                    Snackbar.LENGTH_LONG
                ).show()
            }
        }
    }

    override fun onDestroyView() {
        super.onDestroyView()
        _binding = null
    }
}

// ViewModel (optional but recommended)
class UsersViewModel : ViewModel() {

    private val _users = MutableLiveData<List<User>>()
    val users: LiveData<List<User>> = _users

    private val _isLoading = MutableLiveData<Boolean>()
    val isLoading: LiveData<Boolean> = _isLoading

    private val _error = MutableLiveData<String?>()
    val error: LiveData<String?> = _error

    fun loadUsers() {
        _isLoading.value = true
        _error.value = null

        viewModelScope.launch {
            try {
                val userList = RetrofitClient.apiService.getUsers()
                _users.value = userList
            } catch (e: Exception) {
                _error.value = e.localizedMessage ?: "Unknown error"
            } finally {
                _isLoading.value = false
            }
        }
    }
}

// Extension functions
fun String.capitalizeWords(): String =
    split(" ").joinToString(" ") { it.replaceFirstChar { char -> char.uppercase() } }

// Sealed class for UI states
sealed class UiState {
    object Loading : UiState()
    data class Success(val data: List<User>) : UiState()
    data class Error(val message: String) : UiState()
}

// Usage in Activity
class MainActivity : AppCompatActivity() {

    private val viewModel: UsersViewModel by viewModels()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        // Using Kotlin Android Extensions (or View Binding)
        setupObservers()
        viewModel.loadUsers()
    }

    private fun setupObservers() {
        viewModel.users.observe(this) { users ->
            // Update UI with users
            users?.let { updateUsersList(it) }
        }

        viewModel.isLoading.observe(this) { isLoading ->
            // Show/hide loading indicator
            progressBar.visibility = if (isLoading) View.VISIBLE else View.GONE
        }

        viewModel.error.observe(this) { error ->
            error?.let {
                Snackbar.make(findViewById(android.R.id.content), it, Snackbar.LENGTH_LONG).show()
            }
        }
    }

    private fun updateUsersList(users: List<User>) {
        // Update RecyclerView adapter
        (recyclerView.adapter as? UsersAdapter)?.submitList(users)
    }
}

